<template><main><header><small>GEOAI · BASELINES</small><h1>语义分割基线站</h1><p>完整 U-Net++ 与轻量 DeepLabV3+ 的训练、验证、GeoTIFF 推理和矢量导出。</p></header><el-tabs v-model="tab"><el-tab-pane label="训练" name="train"><el-card><el-form label-position="top"><div class="grid"><el-form-item label="模型"><el-select v-model="form.model"><el-option label="U-Net++" value="unetpp"/><el-option label="DeepLabV3+" value="deeplabv3plus"/></el-select></el-form-item><el-form-item label="Epoch"><el-input-number v-model="form.epochs" :min="1"/></el-form-item></div><el-form-item label="影像目录"><el-input v-model="form.images"/></el-form-item><el-form-item label="标签目录"><el-input v-model="form.masks"/></el-form-item><el-button type="primary" @click="submit('/api/train',form)">开始训练</el-button></el-form></el-card></el-tab-pane><el-tab-pane label="推理" name="predict"><el-card><el-upload drag action="/api/uploads" :on-success="r=>predictForm.input_path=r.path">上传 GeoTIFF</el-upload><el-form label-position="top"><el-form-item label="影像"><el-input v-model="predictForm.input_path"/></el-form-item><el-form-item label="检查点"><el-select v-model="predictForm.checkpoint" style="width:100%"><el-option v-for="m in models.checkpoints||[]" :key="m.path" :label="m.relative_path" :value="m.path"/></el-select></el-form-item><el-button type="primary" @click="submit('/api/predict',predictForm)">开始推理</el-button></el-form></el-card></el-tab-pane></el-tabs><el-card v-if="task" class="task"><b>{{task.stage}} · {{task.status}}</b><el-progress :percentage="task.progress||0"/><p>{{task.message}}</p><pre v-if="task.error">{{task.error.message}}</pre><div v-if="task.result"><a v-for="(path,key) in files(task.result)" :key="path" :href="`/api/download?path=${encodeURIComponent(path)}`">下载 {{key}}</a></div></el-card></main></template><script setup>import{onMounted,reactive,ref}from'vue';import axios from'axios';import{ElMessage}from'element-plus';const tab=ref('train'),task=ref(null),models=reactive({});const form=reactive({model:'unetpp',epochs:20,batch_size:2,size:256,base_channels:32,lr:.0003,val_ratio:.25,seed:42,images:'',masks:''});const predictForm=reactive({input_path:'',checkpoint:''});onMounted(async()=>{const c=(await axios.get('/api/config')).data;form.images=c.default_images;form.masks=c.default_masks;Object.assign(models,(await axios.get('/api/models')).data)});async function submit(url,payload){task.value=(await axios.post(url,payload)).data;poll()}async function poll(){task.value=(await axios.get(`/api/tasks/${task.value.task_id}`)).data;if(['completed','failed','cancelled'].includes(task.value.status)){if(task.value.status==='completed')ElMessage.success('完成');return}setTimeout(poll,1000)}function files(result){const out={};for(const[k,v]of Object.entries(result||{})){if(typeof v==='string'&&/\.(png|tif|gpkg|pth)$/i.test(v))out[k]=v;if(v&&typeof v==='object'&&typeof v.path==='string')out[k]=v.path}return out}</script>
